1	//! A faithful Rust port of the Hughes/Peyton-Jones pretty-printing library
2	//! `Text.PrettyPrint.HughesPJ` (Haskell `pretty` 1.1.3.6, BSD-licensed).
3	//!
4	//! OUT OF THE GPL-ERASURE SURFACE: this layout algebra was clean-roomed by the
5	//! graphdot cluster from the sanctioned BSD source
6	//! (`graphdot/sanctioned/pretty-1.1.3.6/src/Text/PrettyPrint/Annotated/
7	//! HughesPJ.hs`) and is vendored here unchanged (BSD terms permit), plus one
8	//! addition: [`render_with`], a renderer entry point taking an explicit
9	//! integer ribbon width (the theory echo uses width 110 / ribbon 73).
10	//!
11	//! This module implements the `Doc` document model and the combinators, the
12	//! best/fits layout selection, and the `PageMode` renderer: `<>`/`<+>`,
13	//! `$$`/`$+$`, `hcat`/`hsep`/`vcat`, `sep`/`cat`, `fsep`/`fcat`, `nest`/
14	//! `hang`, and the `best`/`nicest`/`fits` fitting logic with `lineLength` and
15	//! `ribbonsPerLine`.
16	//!
17	//! Nothing in this file is tamarin-specific: it is the general layout algebra.
18	//! WHICH combinators the theory echo applies, with what literal strings and
19	//! nesting, is derived from black-box probes and lives in the sibling modules
20	//! (`term`, `signature`, …); this module is the exact engine they feed.
21	//!
22	//! The annotation machinery of the original is elided (this port renders to a
23	//! plain `String`), so `TextBeside` carries the text and its column width
24	//! directly instead of an `AnnotDetails`.
25	//!
26	//! **Evaluation strategy.** The Haskell original relies on lazy evaluation: the
27	//! combinators (`sep`/`fill`/`beside`/`aboveNest`) describe exponentially large
28	//! sets of layouts as union trees, but `best` only ever forces the branches it
29	//! inspects, and `fits` only forces the *first line* of a candidate. A naive
30	//! strict port materializes those whole trees (exponential in the number of
31	//! fill elements). This port mirrors the laziness explicitly: recursive
32	//! combinator continuations are built as [`Doc::Lazy`] thunks (forced on
33	//! demand, memoized), and the `nicest` union choice uses [`fits_ahead`], which
34	//! decides `fits (min w r - sl) (best' ...)` by walking the *unresolved*
35	//! branch's first line only. Both are pure evaluation-order mirrors of the
36	//! sanctioned semantics: the resolved layout is byte-identical.
37	
38	use std::cell::RefCell;
39	use std::rc::Rc;
40	
41	/// The abstract document type. A `Doc` denotes a *set* of layouts; a `Doc` with
42	/// no `Union`/`NoDoc` denotes a single layout. Mirrors the Haskell `Doc a`
43	/// constructors (annotations elided).
44	#[derive(Clone, Debug)]
45	pub enum Doc {
46	    /// An empty span (`empty`): no height, no width.
47	    Empty,
48	    /// `text "" $$ x` — a newline above `x`. Its argument is never `Empty`.
49	    NilAbove(Rc<Doc>),
50	    /// `text s <> x` — literal text (with its column width) beside `x`. The
51	    /// argument is never a `Nest`.
52	    TextBeside(Rc<str>, usize, Rc<Doc>),
53	    /// `nest k x` — indent `x` by `k` columns (`k` may be negative).
54	    Nest(isize, Rc<Doc>),
55	    /// `ul \`union\` ur` — a choice between two layouts that flatten equal.
56	    Union(Rc<Doc>, Rc<Doc>),
57	    /// The empty *set* of documents.
58	    NoDoc,
59	    /// `Beside l sep r` — `sep` = true means a space is inserted between.
60	    Beside(Rc<Doc>, bool, Rc<Doc>),
61	    /// `Above u never_overlap l` — `never_overlap` = true forbids overlap.
62	    Above(Rc<Doc>, bool, Rc<Doc>),
63	    /// A suspended sub-document (the strict mirror of a Haskell thunk):
64	    /// computed on first [`force`], then memoized. Only ever wraps an already
65	    /// *reduced* document (an RDoc — no `Beside`/`Above`).
66	    Lazy(Rc<LazyDoc>),
67	}
68	
69	/// The shared state of a [`Doc::Lazy`] thunk.
70	pub struct LazyDoc(RefCell<LazyState>);
71	
72	enum LazyState {
73	    Pending(Option<Box<dyn FnOnce() -> Doc>>),
74	    Forced(Doc),
75	}
76	
77	impl std::fmt::Debug for LazyDoc {
78	    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
79	        match &*self.0.borrow() {
80	            LazyState::Pending(_) => write!(f, "Lazy(<pending>)"),
81	            LazyState::Forced(d) => write!(f, "Lazy({:?})", d),
82	        }
83	    }
84	}
85	
86	use Doc::*;
87	
88	// ---------------------------------------------------------------------------
89	// Iterative Drop
90	//
91	// A rendered document is a per-LINE linked chain — `NilAbove`/`TextBeside`/
92	// `Nest` interleaved with `Lazy(Forced(..))` thunks (the memoised `best`
93	// output) — as deep as the theory has lines. A huge `variants (modulo AC)`
94	// block (C8 / BP_IBS: ~10 000 lines) makes that chain ~10 000 deep, and the
95	// compiler-generated recursive `Drop` of nested `Rc<Doc>` overflows the stack
96	// on it. This explicit-stack `Drop` dismantles the chain iteratively: each
97	// node's children are detached (swapped for a shared `Empty` placeholder so
98	// the automatic field-drop bottoms out at once) and pushed onto a heap `Vec`,
99	// which is then drained. It never changes rendered output — it only bounds the
100	// drop recursion.
101	
102	thread_local! {
103	    static EMPTY_DOC: Rc<Doc> = Rc::new(Empty);
104	    static EMPTY_LAZY: Rc<LazyDoc> = Rc::new(LazyDoc(RefCell::new(LazyState::Forced(Empty))));
105	}
106	
107	fn empty_doc_placeholder() -> Rc<Doc> {
108	    // `try_with` guards the (unreached-in-practice) case of a `Doc` dropping
109	    // during thread-local teardown; a fresh `Empty` is an equally valid shared
110	    // placeholder.
111	    EMPTY_DOC.try_with(|e| e.clone()).unwrap_or_else(|_| Rc::new(Empty))
112	}
113	
114	fn empty_lazy_placeholder() -> Rc<LazyDoc> {
115	    EMPTY_LAZY
116	        .try_with(|e| e.clone())
117	        .unwrap_or_else(|_| Rc::new(LazyDoc(RefCell::new(LazyState::Forced(Empty)))))
118	}
119	
120	/// Detach `d`'s direct children onto `stack`, replacing each with a shared
121	/// placeholder so `d`'s own field-drop is O(1). A uniquely-owned child yields
122	/// an owned `Doc` (pushed); a shared child (`try_unwrap`/`get_mut` fails) is
123	/// dropped in place — a decrement only, never a deep recursion, since the
124	/// placeholders are always shared and so are never descended into.
125	fn detach_children(d: &mut Doc, stack: &mut Vec<Doc>) {
126	    fn take(p: &mut Rc<Doc>, stack: &mut Vec<Doc>) {
127	        // A leaf child has no children of its own, so its natural drop is O(1)
128	        // and cannot recurse — leave it in place (this keeps the common
129	        // shallow-document drop allocation-free).
130	        if matches!(**p, Empty | NoDoc) {
131	            return;
132	        }
133	        let child = std::mem::replace(p, empty_doc_placeholder());
134	        if let Ok(owned) = Rc::try_unwrap(child) {
135	            stack.push(owned);
136	        }
137	    }
138	    match d {
139	        NilAbove(p) => take(p, stack),
140	        TextBeside(_, _, p) => take(p, stack),
141	        Nest(_, p) => take(p, stack),
142	        Union(a, b) => {
143	            take(a, stack);
144	            take(b, stack);
145	        }
146	        Beside(a, _, b) => {
147	            take(a, stack);
148	            take(b, stack);
149	        }
150	        Above(a, _, b) => {
151	            take(a, stack);
152	            take(b, stack);
153	        }
154	        Lazy(l) => {
155	            let taken = std::mem::replace(l, empty_lazy_placeholder());
156	            if let Ok(ld) = Rc::try_unwrap(taken) {
157	                if let LazyState::Forced(inner) = ld.0.into_inner() {
158	                    stack.push(inner);
159	                }
160	                // Pending: its boxed closure drops with `ld`; the closure's
161	                // captured continuations are shallow (the deep chains are the
162	                // Forced output path handled above).
163	            }
164	        }
165	        Empty | NoDoc => {}
166	    }
167	}
168	
169	impl Drop for Doc {
170	    fn drop(&mut self) {
171	        // Fast path: leaves and already-detached placeholders carry no owned
172	        // children, so there is nothing to dismantle.
173	        if matches!(self, Empty | NoDoc) {
174	            return;
175	        }
176	        let mut stack: Vec<Doc> = Vec::new();
177	        detach_children(self, &mut stack);
178	        while let Some(mut node) = stack.pop() {
179	            // `node`'s children are detached onto the stack; `node` then drops
180	            // with only placeholder children, so its re-entrant `Drop` is O(1).
181	            detach_children(&mut node, &mut stack);
182	        }
183	    }
184	}
185	
186	fn rc(d: Doc) -> Rc<Doc> {
187	    Rc::new(d)
188	}
189	
190	/// Suspend a document computation (a thunk). The closure runs at most once.
191	fn lazy<F: FnOnce() -> Doc + 'static>(f: F) -> Doc {
192	    Lazy(Rc::new(LazyDoc(RefCell::new(LazyState::Pending(Some(
193	        Box::new(f),
194	    ))))))
195	}
196	
197	/// Force a document to its outermost non-`Lazy` constructor (shallow clone —
198	/// children stay shared via `Rc`). Thunks are computed once and memoized;
199	/// chains of thunks collapse to the final value.
200	fn force(d: &Doc) -> Doc {
201	    match d {
202	        Lazy(l) => {
203	            if let LazyState::Forced(v) = &*l.0.borrow() {
204	                return v.clone();
205	            }
206	            let f = match &mut *l.0.borrow_mut() {
207	                LazyState::Pending(f) => f.take().expect("re-entrant force"),
208	                LazyState::Forced(v) => return v.clone(),
209	            };
210	            let v = force(&f());
211	            *l.0.borrow_mut() = LazyState::Forced(v.clone());
212	            v
213	        }
214	        _ => d.clone(),
215	    }
216	}
