218	// ---------------------------------------------------------------------------
219	// Constructors (§ "Values and Predicates")
220	
221	/// A one-character document.
222	pub fn char(c: char) -> Doc {
223	    let mut buf = [0u8; 4];
224	    let s: &str = c.encode_utf8(&mut buf);
225	    TextBeside(Rc::from(s), 1, rc(Empty))
226	}
227	
228	/// A one-line literal string document; its width is its Unicode-scalar count.
229	pub fn text(s: &str) -> Doc {
230	    let len = s.chars().count();
231	    TextBeside(Rc::from(s), len, rc(Empty))
232	}
233	
234	/// Text with an explicit column width (`sizedText l s`); use width 0 for
235	/// non-printing text.
236	pub fn sized_text(len: usize, s: &str) -> Doc {
237	    TextBeside(Rc::from(s), len, rc(Empty))
238	}
239	
240	/// The empty document (identity for `<>`, `$$`, and list combinators).
241	pub fn empty() -> Doc {
242	    Empty
243	}
244	
245	/// Is this the empty document?
246	pub fn is_empty(d: &Doc) -> bool {
247	    matches!(force(d), Empty)
248	}
249	
250	
251	// ---------------------------------------------------------------------------
252	// Structural smart-constructors
253	
254	fn nil_above_(d: Rc<Doc>) -> Doc {
255	    NilAbove(d)
256	}
257	
258	fn text_beside_(s: Rc<str>, l: usize, d: Rc<Doc>) -> Doc {
259	    TextBeside(s, l, d)
260	}
261	
262	fn nest_(k: isize, d: Rc<Doc>) -> Doc {
263	    Nest(k, d)
264	}
265	
266	fn union_(a: Rc<Doc>, b: Rc<Doc>) -> Doc {
267	    Union(a, b)
268	}
269	
270	/// `reduceDoc`: push `Beside`/`Above` down into reduced form (RDoc).
271	///
272	/// Iterative rewrite of the recursive `beside(p,g,&reduce_doc(q))` /
273	/// `above(p,g,&reduce_doc(q))`: the right spine of a `Beside`/`Above` tree can
274	/// be thousands deep (the wide `vcat` of a huge `variants (modulo AC)` block —
275	/// C8 / BP_IBS), so the spine is unrolled onto a heap `Vec` and folded back,
276	/// keeping the recursion off the call stack. The fold order and the
277	/// `beside`/`above` applications are identical to the recursive form, so the
278	/// resulting RDoc — and every rendered byte — is unchanged.
279	pub fn reduce_doc(d: &Doc) -> Doc {
280	    enum Frame {
281	        Beside(Doc, bool),
282	        Above(Doc, bool),
283	    }
284	    let mut frames: Vec<Frame> = Vec::new();
285	    // `Doc` implements `Drop`, so spine nodes are inspected by reference and
286	    // their children shallow-cloned (an `Rc` bump each) rather than moved out.
287	    let mut cur = d.clone();
288	    loop {
289	        let next = match &cur {
290	            Doc::Beside(p, g, q) => {
291	                frames.push(Frame::Beside((**p).clone(), *g));
292	                (**q).clone()
293	            }
294	            Doc::Above(p, g, q) => {
295	                frames.push(Frame::Above((**p).clone(), *g));
296	                (**q).clone()
297	            }
298	            _ => break,
299	        };
300	        cur = next;
301	    }
302	    let mut acc = cur;
303	    for frame in frames.into_iter().rev() {
304	        acc = match frame {
305	            Frame::Beside(p, g) => beside(&p, g, &acc),
306	            Frame::Above(p, g) => above(&p, g, &acc),
307	        };
308	    }
309	    acc
310	}
311	
312	// ---------------------------------------------------------------------------
313	// nest / mkNest / mkUnion
314	
315	/// `nest k p` — indent by `k` (may be negative).
316	pub fn nest(k: isize, p: &Doc) -> Doc {
317	    mk_nest(k, &reduce_doc(p))
318	}
319	
320	fn mk_nest(k: isize, d: &Doc) -> Doc {
321	    let df = force(d);
322	    match &df {
323	        Nest(k1, p) => mk_nest(k + k1, p),
324	        NoDoc => NoDoc,
325	        Empty => Empty,
326	        _ if k == 0 => df,
327	        _ => nest_(k, rc(df)),
328	    }
329	}
330	
331	fn mk_union(p: Doc, q: Doc) -> Doc {
332	    match force(&p) {
333	        Empty => Empty,
334	        pf => union_(rc(pf), rc(q)),
335	    }
336	}
337	
338	// ---------------------------------------------------------------------------
339	// Horizontal composition <> and <+>
340	
341	/// `p <> q` — beside.
342	pub fn beside_op(p: Doc, q: Doc) -> Doc {
343	    beside_(p, false, q)
344	}
345	
346	/// `p <+> q` — beside, separated by a space unless an argument is empty.
347	pub fn beside_space(p: Doc, q: Doc) -> Doc {
348	    beside_(p, true, q)
349	}
350	
351	fn beside_(p: Doc, g: bool, q: Doc) -> Doc {
352	    match (&p, &q) {
353	        (_, Empty) => p,
354	        (Empty, _) => q,
355	        _ => Beside(rc(p), g, rc(q)),
356	    }
357	}
358	
359	/// `beside p g q` (spec: `p <g> q`) over reduced docs. Union branches and the
360	/// text-tail continuation are suspended ([`lazy`]), mirroring the sanctioned
361	/// source's (non-`$!`) laziness.
362	fn beside(p: &Doc, g: bool, q: &Doc) -> Doc {
363	    let pf = force(p);
364	    match &pf {
365	        NoDoc => NoDoc,
366	        Union(p1, p2) => {
367	            let (p1, p2, qa, qb) = (p1.clone(), p2.clone(), q.clone(), q.clone());
368	            union_(
369	                rc(lazy(move || beside(&p1, g, &qa))),
370	                rc(lazy(move || beside(&p2, g, &qb))),
371	            )
372	        }
373	        Empty => q.clone(),
374	        Nest(k, p1) => nest_(*k, rc(beside(p1, g, q))),
375	        Beside(p1, g1, q1) => {
376	            if *g1 == g {
377	                beside(p1, *g1, &beside(q1, g, q))
378	            } else {
379	                beside(&reduce_doc(&pf), g, q)
380	            }
381	        }
382	        Above(..) => beside(&reduce_doc(&pf), g, q),
383	        NilAbove(p1) => nil_above_(rc(beside(p1, g, q))),
384	        TextBeside(s, l, p1) => {
385	            let (p1, q1) = (p1.clone(), q.clone());
386	            let rest = lazy(move || match force(&p1) {
387	                Empty => nil_beside(g, &q1),
388	                _ => beside(&p1, g, &q1),
389	            });
390	            text_beside_(s.clone(), *l, rc(rest))
391	        }
392	        Lazy(_) => unreachable!("beside: forced doc"),
393	    }
394	}
395	
396	/// `nilBeside g p` (spec: `text "" <g> p`).
397	fn nil_beside(g: bool, p: &Doc) -> Doc {
398	    let pf = force(p);
399	    match &pf {
400	        Empty => Empty,
401	        Nest(_, p1) => nil_beside(g, p1),
402	        _ => {
403	            if g {
404	                TextBeside(Rc::from(" "), 1, rc(pf))
405	            } else {
406	                pf
407	            }
408	        }
409	    }
410	}
411	
412	// ---------------------------------------------------------------------------
413	// Vertical composition $$ and $+$
414	
415	/// `p $$ q` — above, with overlap allowed.
416	pub fn above_op(p: Doc, q: Doc) -> Doc {
417	    above_(p, false, q)
418	}
419	
420	/// `p $+$ q` — above, no overlap.
421	pub fn above_plus(p: Doc, q: Doc) -> Doc {
422	    above_(p, true, q)
423	}
424	
425	fn above_(p: Doc, g: bool, q: Doc) -> Doc {
426	    match (&p, &q) {
427	        (_, Empty) => p,
428	        (Empty, _) => q,
429	        _ => Above(rc(p), g, rc(q)),
430	    }
431	}
432	
433	fn above(p: &Doc, g: bool, q: &Doc) -> Doc {
434	    let pf = force(p);
435	    match &pf {
436	        Above(p1, g1, q1) => above(p1, *g1, &above(q1, g, q)),
437	        Beside(..) => above_nest(&reduce_doc(&pf), g, 0, &reduce_doc(q)),
438	        _ => above_nest(&pf, g, 0, &reduce_doc(q)),
439	    }
440	}
441	
442	/// `aboveNest p g k q` (spec: `p $g$ (nest k q)`). Union branches and the
443	/// recursive continuations are suspended, mirroring the sanctioned laziness.
444	fn above_nest(p: &Doc, g: bool, k: isize, q: &Doc) -> Doc {
445	    let pf = force(p);
446	    match &pf {
447	        NoDoc => NoDoc,
448	        Union(p1, p2) => {
449	            let (p1, p2, qa, qb) = (p1.clone(), p2.clone(), q.clone(), q.clone());
450	            union_(
451	                rc(lazy(move || above_nest(&p1, g, k, &qa))),
452	                rc(lazy(move || above_nest(&p2, g, k, &qb))),
453	            )
454	        }
455	        Empty => mk_nest(k, q),
456	        Nest(k1, p1) => {
457	            let (k1, p1, q1) = (*k1, p1.clone(), q.clone());
458	            nest_(k1, rc(lazy(move || above_nest(&p1, g, k - k1, &q1))))
459	        }
460	        NilAbove(p1) => {
461	            let (p1, q1) = (p1.clone(), q.clone());
462	            nil_above_(rc(lazy(move || above_nest(&p1, g, k, &q1))))
463	        }
464	        TextBeside(s, l, p1) => {
465	            let k1 = k - (*l as isize);
466	            let (p1, q1) = (p1.clone(), q.clone());
467	            let rest = lazy(move || match force(&p1) {
468	                Empty => nil_above_nest(g, k1, &q1),
469	                _ => above_nest(&p1, g, k1, &q1),
470	            });
471	            text_beside_(s.clone(), *l, rc(rest))
472	        }
473	        Above(..) => panic!("aboveNest Above"),
474	        Beside(..) => panic!("aboveNest Beside"),
475	        Lazy(_) => unreachable!("aboveNest: forced doc"),
476	    }
477	}
478	
479	/// `nilAboveNest g k q` (spec: `text s <> (text "" $g$ nest k q)`).
480	fn nil_above_nest(g: bool, k: isize, q: &Doc) -> Doc {
481	    let qf = force(q);
482	    match &qf {
483	        Empty => Empty,
484	        Nest(k1, q1) => nil_above_nest(g, k + k1, q1),
485	        _ => {
486	            if !g && k > 0 {
487	                let ind = indent(k);
488	                let len = ind.chars().count();
489	                text_beside_(Rc::from(ind.as_str()), len, rc(qf))
490	            } else {
491	                nil_above_(rc(mk_nest(k, &qf)))
492	            }
493	        }
494	    }
495	}
496	
497	// ---------------------------------------------------------------------------
498	// List versions: hcat / hsep / vcat  (via reduceHoriz/reduceVert)
499	
500	#[derive(Clone, Copy)]
501	enum IsEmpty {
502	    // `Empty` mirrors the Haskell `reduceHoriz`/`reduceVert` return type; this
503	    // strict port only ever yields `NotEmpty`, but the variant is kept to match
504	    // the sanctioned source's shape.
505	    #[allow(dead_code)]
506	    Empty,
507	    NotEmpty,
508	}
509	
510	// `reduce_horiz`/`reduce_vert` fold a right-nested `Beside`/`Above` spine (the
511	// list built by `hcat`/`hsep`/`vcat`) into reduced form. That spine is as long
512	// as the list — thousands of rows for a huge `variants (modulo AC)` block — so
513	// both walk the spine iteratively onto a heap `Vec` and fold it back with
514	// `eliminate_empty`, exactly as the recursive form did, off the call stack.
515	// The left component of each spine node (`p`) is a single list item and is
516	// reduced recursively (bounded by that item's own depth).
517	
518	// The `loop { let next = match &cur {…}; cur = next }` idiom cannot become a
519	// `while let` here: the arm reassigns `cur`, which is still borrowed by the
520	// `while let` scrutinee.
521	#[allow(clippy::while_let_loop)]
522	fn reduce_horiz(d: &Doc) -> (IsEmpty, Doc) {
523	    let mut lefts: Vec<(Doc, bool)> = Vec::new();
524	    let mut cur = d.clone();
525	    loop {
526	        let next = match &cur {
527	            Beside(p, g, q) => {
528	                let (_, pr) = reduce_horiz(p);
529	                lefts.push((pr, *g));
530	                (**q).clone()
531	            }
532	            _ => break,
533	        };
534	        cur = next;
535	    }
536	    let mut acc = (IsEmpty::NotEmpty, cur);
537	    for (pr, g) in lefts.into_iter().rev() {
538	        acc = eliminate_empty(true, pr, g, acc);
539	    }
540	    acc
541	}
542	
543	#[allow(clippy::while_let_loop)] // see `reduce_horiz`: the arm reassigns `cur`.
544	fn reduce_vert(d: &Doc) -> (IsEmpty, Doc) {
545	    let mut lefts: Vec<(Doc, bool)> = Vec::new();
546	    let mut cur = d.clone();
547	    loop {
548	        let next = match &cur {
549	            Above(p, g, q) => {
550	                let (_, pr) = reduce_vert(p);
551	                lefts.push((pr, *g));
552	                (**q).clone()
553	            }
554	            _ => break,
555	        };
556	        cur = next;
557	    }
558	    let mut acc = (IsEmpty::NotEmpty, cur);
559	    for (pr, g) in lefts.into_iter().rev() {
560	        acc = eliminate_empty(false, pr, g, acc);
561	    }
562	    acc
563	}
564	
565	/// `beside_cons` = true builds `Beside`, false builds `Above`.
566	fn eliminate_empty(beside_cons: bool, p: Doc, g: bool, q: (IsEmpty, Doc)) -> (IsEmpty, Doc) {
567	    match p {
568	        Empty => q,
569	        _ => {
570	            let out = match q {
571	                (IsEmpty::NotEmpty, q1) => {
572	                    if beside_cons {
573	                        Beside(rc(p), g, rc(q1))
574	                    } else {
575	                        Above(rc(p), g, rc(q1))
576	                    }
577	                }
578	                (IsEmpty::Empty, _) => p,
579	            };
580	            (IsEmpty::NotEmpty, out)
581	        }
582	    }
583	}
