715	// fill (fcat / fsep)
716	
717	/// `fcat` — paragraph-fill version of `cat` (no inter-element space).
718	pub fn fcat(ds: Vec<Doc>) -> Doc {
719	    fill(false, ds)
720	}
721	
722	/// `fsep` — paragraph-fill version of `sep` (space between elements).
723	pub fn fsep(ds: Vec<Doc>) -> Doc {
724	    fill(true, ds)
725	}
726	
727	fn fill(g: bool, ds: Vec<Doc>) -> Doc {
728	    if ds.is_empty() {
729	        return Empty;
730	    }
731	    let mut it = ds.into_iter();
732	    let p = it.next().unwrap();
733	    let ys: Vec<Doc> = it.collect();
734	    fill1(g, &reduce_doc(&p), 0, &ys)
735	}
736	
737	fn fill1(g: bool, p: &Doc, k: isize, ys: &[Doc]) -> Doc {
738	    let pf = force(p);
739	    match &pf {
740	        NoDoc => NoDoc,
741	        Union(p1, q) => {
742	            let (p1, q) = (p1.clone(), q.clone());
743	            let (ya, yb) = (ys.to_vec(), ys.to_vec());
744	            union_(
745	                rc(lazy(move || fill1(g, &p1, k, &ya))),
746	                rc(lazy(move || above_nest(&q, false, k, &fill(g, yb)))),
747	            )
748	        }
749	        Empty => mk_nest(k, &fill(g, ys.to_vec())),
750	        Nest(n, p1) => {
751	            let (n, p1, ys) = (*n, p1.clone(), ys.to_vec());
752	            nest_(n, rc(lazy(move || fill1(g, &p1, k - n, &ys))))
753	        }
754	        NilAbove(p1) => {
755	            let (p1, ys) = (p1.clone(), ys.to_vec());
756	            nil_above_(rc(lazy(move || {
757	                above_nest(&p1, false, k, &fill(g, ys))
758	            })))
759	        }
760	        TextBeside(s, l, p1) => {
761	            let li = *l as isize;
762	            let (p1, ys) = (p1.clone(), ys.to_vec());
763	            text_beside_(
764	                s.clone(),
765	                *l,
766	                rc(lazy(move || fill_nb(g, &p1, k - li, &ys))),
767	            )
768	        }
769	        Above(..) => panic!("fill1 Above"),
770	        Beside(..) => panic!("fill1 Beside"),
771	        Lazy(_) => unreachable!("fill1: forced doc"),
772	    }
773	}
774	
775	fn fill_nb(g: bool, p: &Doc, k: isize, ys: &[Doc]) -> Doc {
776	    let pf = force(p);
777	    match &pf {
778	        Nest(_, p1) => fill_nb(g, p1, k, ys),
779	        Empty => {
780	            if ys.is_empty() {
781	                Empty
782	            } else if matches!(force(&ys[0]), Empty) {
783	                fill_nb(g, &Empty, k, &ys[1..])
784	            } else {
785	                fill_nbe(g, k, &ys[0], &ys[1..])
786	            }
787	        }
788	        _ => fill1(g, &pf, k, ys),
789	    }
790	}
791	
792	fn fill_nbe(g: bool, k: isize, y: &Doc, ys: &[Doc]) -> Doc {
793	    let k1 = if g { k - 1 } else { k };
794	    let y_one = elide_nest(&one_liner(&reduce_doc(y)));
795	    let left = nil_beside(g, &fill1(g, &y_one, k1, ys));
796	    let (y2, ys2) = (y.clone(), ys.to_vec());
797	    let right = lazy(move || {
798	        let mut rest = vec![y2];
799	        rest.extend(ys2);
800	        nil_above_nest(false, k, &fill(g, rest))
801	    });
802	    mk_union(left, right)
803	}
804	
805	fn elide_nest(d: &Doc) -> Doc {
806	    let df = force(d);
807	    match &df {
808	        Nest(_, d1) => d1.as_ref().clone(),
809	        _ => df,
810	    }
811	}
