961	/// Render a document in `PageMode` at line length `line_len` and
962	/// `ribbons_per_line`, producing the plain string (newline-separated lines,
963	/// each continuation prefixed by its indentation spaces).
964	pub fn render_page(line_len: isize, ribbons_per_line: f64, doc: &Doc) -> String {
965	    let ribbon_len = round_ribbon(line_len, ribbons_per_line);
966	    let reduced = reduce_doc(doc);
967	    let best_doc = best(line_len, ribbon_len, &reduced);
968	    display_page(line_len, ribbon_len, &best_doc)
969	}
