971	/// Render in `PageMode` with an EXPLICIT ribbon width (columns), bypassing the
972	/// `ribbons_per_line` division. The theory echo renders at `render_with(110,
973	/// 73, doc)`.
974	pub fn render_with(line_len: isize, ribbon_len: isize, doc: &Doc) -> String {
975	    let reduced = reduce_doc(doc);
976	    let best_doc = best(line_len, ribbon_len, &reduced);
977	    display_page(line_len, ribbon_len, &best_doc)
978	}
