191	/// One FULL rule block (header + body + blank + variants comment) — the MSR
192	/// rules-pane form.
193	pub fn render_rule_block(r: &Rule, variants: Option<&AcVariants>) -> String {
194	    html_render(|| rule::block_doc(r, variants))
195	}
