197	/// One restriction block (statement, `// safety formula`, expanded-formula
198	/// comment) — the rules-pane restrictions form.
199	pub fn render_restriction(r: &Restriction) -> String {
200	    html_render(|| lemma::restriction_doc(r))
201	}
