203	/// One formula in bare (top-level) position at web params — for source views
204	/// and lemma statements (UNVALIDATED: no formula-only web capture; reuses the
205	/// restriction-validated operator spans).
206	pub fn render_formula(f: &crate::ast::Formula) -> String {
