210	// ── section-body assemblers ──────────────────────────────────────────────────
211	
212	/// A `Construction Rules` / `Deconstruction Rules` message-pane body: BARE
213	/// rules joined by one blank line.
214	pub fn render_bare_rules_body(rules: &[Rule]) -> String {
215	    rules
216	        .iter()
217	        .map(render_rule_bare)
218	        .collect::<Vec<_>>()
219	        .join("\n\n")
220	}
