222	/// The `Multiset Rewriting Rules` rules-pane body: FULL rule blocks joined by
223	/// TWO blank lines after a `modulo AC` rule and ZERO after a `modulo E` rule
224	/// (corpus: 164 AC→2 / 942 E→0), no trailing.
225	pub fn render_msr_body(rules: &[(Rule, Option<AcVariants>)]) -> String {
226	    let mut out = String::new();
227	    for (i, (r, v)) in rules.iter().enumerate() {
228	        if i > 0 {
229	            let prev = &rules[i - 1].0;
230	            out.push_str(if prev.modulo.as_deref() == Some("AC") {
231	                "\n\n\n"
232	            } else {
233	                "\n"
234	            });
235	        }
236	        out.push_str(&render_rule_block(r, v.as_ref()));
237	    }
238	    out
239	}
