36	fn decode_json_string(s: &str) -> (String, usize) {
37	    let bytes = s.as_bytes();
38	    let mut out = String::new();
39	    let mut i = 0;
40	    loop {
41	        match bytes[i] {
42	            b'"' => return (out, i),
43	            b'\\' => {
44	                i += 1;
45	                match bytes[i] {
46	                    b'"' => out.push('"'),
47	                    b'\\' => out.push('\\'),
48	                    b'/' => out.push('/'),
49	                    b'n' => out.push('\n'),
50	                    b't' => out.push('\t'),
51	                    b'r' => out.push('\r'),
52	                    b'b' => out.push('\u{8}'),
53	                    b'f' => out.push('\u{c}'),
54	                    b'u' => {
55	                        let cp = u32::from_str_radix(&s[i + 1..i + 5], 16).unwrap();
56	                        i += 4;
57	                        out.push(char::from_u32(cp).unwrap());
58	                    }
59	                    other => panic!("bad escape \\{}", other as char),
60	                }
61	                i += 1;
62	            }
63	            _ => {
64	                let c = s[i..].chars().next().unwrap();
65	                out.push(c);
66	                i += c.len_utf8();
67	            }
68	        }
69	    }
70	}
