85	fn unpostprocess(html: &str) -> Vec<String> {
86	    assert!(html.ends_with("<br/>\n"), "postprocessed fragment");
87	    let mut lines: Vec<&str> = html.split("<br/>\n").collect();
88	    assert_eq!(lines.pop(), Some(""));
89	    lines
90	        .iter()
91	        .map(|line| {
92	            let mut rest = *line;
93	            let mut n = 0;
94	            while let Some(r) = rest.strip_prefix("&nbsp;") {
95	                rest = r;
96	                n += 1;
97	            }
98	            format!("{}{}", " ".repeat(n), rest)
99	        })
100	        .collect()
