103	/// (leading_blank, [(heading, body_lines)]).
104	fn parse_blocks(lines: &[String]) -> (bool, Vec<(String, Vec<String>)>) {
105	    let mut i = 0;
106	    let leading_blank = lines.first().is_some_and(|l| l.is_empty());
107	    if leading_blank {
108	        i = 1;
109	    }
110	    let mut blocks = Vec::new();
111	    while i < lines.len() {
112	        let heading = lines[i]
113	            .strip_prefix("<h2>")
114	            .and_then(|h| h.strip_suffix("</h2>"))
115	            .unwrap_or_else(|| panic!("expected heading, got {:?}", lines[i]))
116	            .to_string();
117	        i += 1;
118	        let first = lines[i]
119	            .strip_prefix(P_OPEN)
120	            .unwrap_or_else(|| panic!("expected <p>, got {:?}", lines[i]));
121	        let mut body = Vec::new();
122	        let mut cur = first.to_string();
123	        loop {
124	            if let Some(stripped) = cur.strip_suffix("</p>") {
125	                if !(stripped.is_empty() && body.is_empty()) {
126	                    body.push(stripped.to_string());
127	                }
128	                i += 1;
129	                break;
130	            }
131	            body.push(cur);
132	            i += 1;
133	            cur = lines[i].clone();
134	        }
135	        blocks.push((heading, body));
136	    }
137	    (leading_blank, blocks)
138	}
