140	fn strip_spans(s: &str) -> String {
141	    let mut out = String::with_capacity(s.len());
142	    let mut rest = s;
143	    while let Some(i) = rest.find('<') {
144	        out.push_str(&rest[..i]);
145	        let close = rest[i..].find('>').expect("span tag close") + i;
146	        let tag = &rest[i..=close];
147	        assert!(
148	            tag.starts_with("<span ") || tag == "</span>",
149	            "unexpected tag in body: {tag:?}"
150	        );
151	        rest = &rest[close + 1..];
152	    }
153	    out.push_str(rest);
154	    out
155	}
156	
157	fn unescape(s: &str) -> String {
158	    let mut out = String::with_capacity(s.len());
159	    let mut rest = s;
160	    while let Some(i) = rest.find('&') {
161	        out.push_str(&rest[..i]);
162	        rest = &rest[i..];
163	        let (c, len) = if rest.starts_with("&amp;") {
164	            ('&', 5)
165	        } else if rest.starts_with("&lt;") {
166	            ('<', 4)
167	        } else if rest.starts_with("&gt;") {
168	            ('>', 4)
169	        } else if rest.starts_with("&quot;") {
170	            ('"', 6)
171	        } else if rest.starts_with("&#39;") {
172	            ('\'', 5)
173	        } else {
174	            panic!("unknown entity {:?}", &rest[..rest.len().min(8)]);
175	        };
176	        out.push(c);
177	        rest = &rest[len..];
178	    }
179	    out.push_str(rest);
180	    out
181	}
