183	/// The captured body of a block as plain text (spans stripped, entities
184	/// unescaped, leading indent spaces preserved).
185	fn plain(body: &[String]) -> String {
186	    body.iter()
187	        .map(|l| unescape(&strip_spans(l)))
188	        .collect::<Vec<_>>()
189	        .join("\n")
190	}
