194	/// Split a plain-text section into blocks at col-0 lines matching `head`,
195	/// trimming the blank lines between blocks.
196	fn split_at_heads(plain: &str, head: &str) -> Vec<String> {
197	    let lines: Vec<&str> = plain.lines().collect();
198	    let starts: Vec<usize> = lines
199	        .iter()
200	        .enumerate()
201	        .filter(|(_, l)| l.starts_with(head))
202	        .map(|(i, _)| i)
203	        .collect();
204	    let mut out = Vec::new();
205	    for (k, &a) in starts.iter().enumerate() {
206	        let end = starts.get(k + 1).copied().unwrap_or(lines.len());
207	        let mut b = end;
208	        while b > a + 1 && lines[b - 1].is_empty() {
209	            b -= 1;
210	        }
211	        out.push(lines[a..b].join("\n"));
212	    }
213	    out
214	}
