219	fn escape_heading(s: &str) -> String {
220	    s.replace('&', "&amp;")
221	        .replace('<', "&lt;")
222	        .replace('>', "&gt;")
223	        .replace('"', "&quot;")
224	        .replace('\'', "&#39;")
225	}
