227	fn postprocess(assembled: &str) -> String {
228	    let mut out = String::new();
229	    for line in assembled.split('\n') {
230	        let text = line.trim_start_matches(' ');
231	        for _ in 0..line.len() - text.len() {
232	            out.push_str("&nbsp;");
233	        }
234	        out.push_str(text);
235	        out.push_str("<br/>\n");
236	    }
237	    out
238	}
