240	fn json_escape(s: &str) -> String {
241	    let mut out = String::new();
242	    for c in s.chars() {
243	        match c {
244	            '"' => out.push_str("\\\""),
245	            '\\' => out.push_str("\\\\"),
246	            '\n' => out.push_str("\\n"),
247	            '\t' => out.push_str("\\t"),
248	            _ => out.push(c),
249	        }
250	    }
251	    out
252	}
