254	/// Reassemble a pane the way producers `render_pane` does: `<h2>`/`<p>` block
255	/// skeleton (empty blocks per their mode), postprocess, `{html,title}` envelope.
256	fn reassemble(
257	    title: &str,
258	    leading_blank: bool,
259	    blocks: &[(&str, Option<&str>)], // (heading, Some(body) | None = omitted)
260	) -> String {
261	    let mut chunks: Vec<String> = Vec::new();
262	    if leading_blank {
263	        chunks.push(String::new());
264	    }
265	    for (heading, body) in blocks {
266	        let Some(body) = body else { continue };
267	        let mut chunk = String::new();
268	        chunk.push_str("<h2>");
269	        chunk.push_str(&escape_heading(heading));
270	        chunk.push_str("</h2>\n");
271	        chunk.push_str(P_OPEN);
272	        chunk.push_str(body);
273	        chunk.push_str("</p>");
274	        chunks.push(chunk);
275	    }
276	    let html = postprocess(&chunks.join("\n"));
277	    format!(
278	        "{{\"html\":\"{}\",\"title\":\"{}\"}}",
279	        json_escape(&html),
280	        json_escape(title)
281	    )
282	}
