421	/// Strip spans, unescape entities, collapse all whitespace runs to one space —
422	/// the layout-independent token content.
423	fn norm_content(s: &str) -> String {
424	    let plain = unescape(&strip_spans(s));
425	    plain.split_whitespace().collect::<Vec<_>>().join(" ")
