428	/// The ordered sequence of (class, whitespace-collapsed inner-text) spans.
429	fn span_seq(s: &str) -> Vec<(String, String)> {
430	    let mut out = Vec::new();
431	    let mut rest = s;
432	    // spans may straddle lines and nest; walk opening tags and match to the
433	    // NEXT closing tag at the same depth via a simple stack.
434	    let mut stack: Vec<(String, usize)> = Vec::new();
435	    let bytes = s;
436	    let mut pos = 0;
437	    let _ = (&mut rest, &bytes);
438	    while let Some(i) = s[pos..].find('<') {
439	        let at = pos + i;
440	        let close = s[at..].find('>').unwrap() + at;
441	        let tag = &s[at..=close];
442	        if let Some(cls) = tag
443	            .strip_prefix("<span class=\"")
444	            .and_then(|t| t.strip_suffix("\">"))
445	        {
446	            stack.push((cls.to_string(), close + 1));
447	        } else if tag == "</span>" {
448	            if let Some((cls, start)) = stack.pop() {
449	                let inner = &s[start..at];
450	                let inner_plain = unescape(&strip_spans(inner));
451	                out.push((cls, inner_plain.split_whitespace().collect::<Vec<_>>().join(" ")));
452	            }
453	        }
454	        pos = close + 1;
455	    }
456	    out.sort();
457	    out
458	}
