1	//! Layout-insensitive echo parser (test harness only), shared by the R6 web
2	//! acceptance sweep. Copied from the round-5 inline parser (which is left
3	//! untouched) so the R1–R5 suites are not perturbed; it consults only token
4	//! order, never layout, so it parses the web mode's width-100 plain text (spans
5	//! stripped, entities unescaped) into the same model the batch echo yields.
6	
7	#![allow(dead_code)]
8	
9	use pretty_clean::ast::*;
10	
11	pub struct P<'a> {
12	    pub s: &'a str,
13	    pub pos: usize,
14	}
15	
16	impl<'a> P<'a> {
17	    pub fn new(s: &'a str) -> Self {
18	        P { s, pos: 0 }
19	    }
20	    pub fn rest(&self) -> &'a str {
21	        &self.s[self.pos..]
22	    }
23	    pub fn ws(&mut self) {
24	        while let Some(c) = self.rest().chars().next() {
25	            if c.is_whitespace() {
26	                self.pos += c.len_utf8();
27	            } else {
28	                break;
29	            }
30	        }
31	    }
32	    pub fn starts(&mut self, tok: &str) -> bool {
33	        self.ws();
34	        self.rest().starts_with(tok)
35	    }
36	    pub fn eat(&mut self, tok: &str) -> bool {
37	        if self.starts(tok) {
38	            self.pos += tok.len();
39	            true
40	        } else {
41	            false
42	        }
43	    }
44	    pub fn expect(&mut self, tok: &str) {
45	        assert!(
46	            self.eat(tok),
47	            "expected {tok:?} at …{:?}",
48	            &self.rest()[..self.rest().len().min(70)]
49	        );
50	    }
51	    pub fn ident(&mut self) -> String {
52	        self.ws();
53	        let s: String = self
54	            .rest()
55	            .chars()
56	            .take_while(|c| c.is_ascii_alphanumeric() || *c == '_')
57	            .collect();
58	        assert!(
59	            !s.is_empty(),
60	            "expected ident at …{:?}",
61	            &self.rest()[..self.rest().len().min(50)]
62	        );
63	        self.pos += s.len();
64	        s
65	    }
66	    pub fn digits(&mut self) -> String {
67	        let s: String = self
68	            .rest()
69	            .chars()
70	            .take_while(|c| c.is_ascii_digit())
71	            .collect();
72	        self.pos += s.len();
73	        s
74	    }
75	    pub fn name_idx(&mut self) -> (String, u64) {
76	        let name = self.ident();
77	        if self.rest().starts_with('.')
78	            && self.s[self.pos + 1..]
79	                .chars()
80	                .next()
81	                .is_some_and(|c| c.is_ascii_digit())
82	        {
83	            self.pos += 1;
84	            let idx = self.digits().parse().unwrap();
85	            (name, idx)
86	        } else {
87	            (name, 0)
88	        }
89	    }
90	    pub fn quoted(&mut self) -> String {
91	        self.expect("'");
92	        let end = self.rest().find('\'').expect("unterminated quote");
93	        let s = self.rest()[..end].to_string();
94	        self.pos += end + 1;
95	        s
96	    }
97	
98	    pub fn term(&mut self) -> Term {
99	        let mut t = self.atom();
100	        while self.starts("^") {
101	            self.pos += 1;
102	            let rhs = self.atom();
103	            t = Term::BinOp(BinOp::Exp, Box::new(t), Box::new(rhs));
104	        }
105	        t
106	    }
107	    fn sorted_var(&mut self, sort: SortHint) -> Term {
108	        let (name, idx) = self.name_idx();
109	        Term::Var(VarSpec { name, idx, sort, typ: None })
110	    }
111	    fn atom(&mut self) -> Term {
112	        self.ws();
113	        let c = self.rest().chars().next().expect("term expected");
114	        match c {
115	            '\'' => Term::PubLit(self.quoted()),
116	            '~' => {
117	                self.pos += 1;
118	                if self.rest().starts_with('\'') {
119	                    Term::FreshLit(self.quoted())
120	                } else {
121	                    self.sorted_var(SortHint::Fresh)
122	                }
123	            }
124	            '$' => {
125	                self.pos += 1;
126	                self.sorted_var(SortHint::Pub)
127	            }
128	            '#' => {
129	                self.pos += 1;
130	                self.sorted_var(SortHint::Node)
131	            }
132	            '%' => {
133	                self.pos += 1;
134	                if self.rest().chars().next().is_some_and(|c| c.is_ascii_digit()) {
135	                    Term::NatLit(self.digits())
136	                } else {
137	                    self.sorted_var(SortHint::Nat)
138	                }
139	            }
140	            '<' => {
141	                self.pos += 1;
142	                let mut elems = vec![self.term()];
143	                while self.eat(",") {
144	                    elems.push(self.term());
145	                }
146	                self.expect(">");
147	                Term::Pair(elems)
148	            }
149	            '(' => {
150	                self.pos += 1;
151	                let first = self.term();
152	                let op = if self.starts("++") {
153	                    BinOp::Union
154	                } else if self.starts("%+") {
155	                    BinOp::NatPlus
156	                } else if self.starts("\u{2295}") {
157	                    BinOp::Xor
158	                } else if self.starts("*") {
159	                    BinOp::Mult
160	                } else {
161	                    panic!("AC operator expected at …{:?}", &self.rest()[..self.rest().len().min(50)]);
162	                };
163	                let glyph = match op {
164	                    BinOp::Union => "++",
165	                    BinOp::NatPlus => "%+",
166	                    BinOp::Xor => "\u{2295}",
167	                    BinOp::Mult => "*",
168	                    BinOp::Exp => unreachable!(),
169	                };
170	                let mut t = first;
171	                while self.eat(glyph) {
172	                    let rhs = self.term();
173	                    t = Term::BinOp(op, Box::new(t), Box::new(rhs));
174	                }
175	                self.expect(")");
176	                t
177	            }
178	            _ => {
179	                let (name, idx) = self.name_idx();
180	                if self.rest().starts_with('(') {
181	                    self.pos += 1;
182	                    let mut args = vec![self.term()];
183	                    while self.eat(",") {
184	                        args.push(self.term());
185	                    }
186	                    self.expect(")");
187	                    Term::App(name, args)
188	                } else {
189	                    Term::Var(VarSpec { name, idx, sort: SortHint::Untagged, typ: None })
190	                }
191	            }
192	        }
193	    }
194	
195	    pub fn fact(&mut self) -> Fact {
196	        self.ws();
197	        let persistent = self.eat("!");
198	        let name = self.ident();
199	        self.expect("(");
200	        self.ws();
201	        let mut args = Vec::new();
202	        if !self.rest().starts_with(')') {
203	            args.push(self.term());
204	            while self.eat(",") {
205	                args.push(self.term());
206	            }
207	        }
208	        self.expect(")");
209	        let mut annotations = Vec::new();
210	        if self.rest().starts_with('[') {
211	            self.pos += 1;
212	            loop {
213	                self.ws();
214	                if self.eat("+") {
215	                    annotations.push(FactAnnotation::SolveFirst);
216	                } else if self.eat("-") {
217	                    annotations.push(FactAnnotation::SolveLast);
218	                } else if self.eat("no_precomp") {
219	                    annotations.push(FactAnnotation::NoSources);
220	                } else {
221	                    panic!("annotation expected");
222	                }
223	                if !self.eat(",") {
224	                    break;
225	                }
226	            }
227	            self.expect("]");
228	        }
229	        Fact { persistent, name, args, annotations }
230	    }
231	    fn fact_seq(&mut self, close: &str) -> Vec<Fact> {
232	        self.ws();
233	        let mut facts = Vec::new();
234	        if !self.starts(close) {
235	            facts.push(self.fact());
236	            while self.eat(",") {
237	                facts.push(self.fact());
238	            }
239	        }
240	        self.expect(close);
241	        facts
242	    }
243	
244	    pub fn rule_core(&mut self) -> Rule {
245	        self.expect("rule");
246	        self.ws();
247	        let modulo = if self.eat("(modulo") {
248	            let m = self.ident();
249	            self.expect(")");
250	            Some(m)
251	        } else {
252	            None
253	        };
254	        self.ws();
255	        let name: String = self
256	            .rest()
257	            .chars()
258	            .take_while(|c| !matches!(c, '[' | ':') && !c.is_whitespace())
259	            .collect();
260	        self.pos += name.len();
261	        let mut attributes = Vec::new();
262	        if self.rest().starts_with('[') {
263	            self.pos += 1;
264	            loop {
265	                self.ws();
266	                if self.eat("color=#") {
267	                    let v: String = self.rest().chars().take_while(|c| c.is_ascii_alphanumeric()).collect();
268	                    self.pos += v.len();
