354	        self.ws();
355	        if self.rest().starts_with('\u{2200}') {
356	            return self.quantifier("\u{2200}");
357	        }
358	        if self.rest().starts_with('\u{2203}') {
359	            return self.quantifier("\u{2203}");
360	        }
361	        let l = self.funit();
362	        self.ws();
363	        for (glyph, ctor) in [
364	            ("\u{2227}", Formula::And as fn(_, _) -> _),
365	            ("\u{2228}", Formula::Or as fn(_, _) -> _),
366	            ("\u{21d2}", Formula::Implies as fn(_, _) -> _),
367	            ("\u{21d4}", Formula::Iff as fn(_, _) -> _),
368	        ] {
369	            if self.eat(glyph) {
370	                let r = self.funit();
371	                return ctor(Box::new(l), Box::new(r));
