376	    fn funit(&mut self) -> Formula {
377	        self.ws();
378	        if self.eat("\u{22a4}") {
379	            return Formula::True;
380	        }
381	        if self.eat("\u{22a5}") {
382	            return Formula::False;
383	        }
384	        if self.eat("\u{ac}") {
385	            self.expect("(");
386	            let f = self.formula();
387	            self.expect(")");
388	            return Formula::Not(Box::new(f));
389	        }
390	        if self.rest().starts_with('\u{2200}') {
391	            return self.quantifier("\u{2200}");
392	        }
393	        if self.rest().starts_with('\u{2203}') {
394	            return self.quantifier("\u{2203}");
395	        }
396	        if self.rest().starts_with('(') && !self.paren_is_term() {
397	            self.pos += 1;
398	            let f = self.formula();
399	            self.expect(")");
400	            return f;
401	        }
402	        self.formula_atom()
