404	    fn paren_is_term(&self) -> bool {
405	        let bytes = self.rest();
406	        let mut depth = 0usize;
407	        let mut it = bytes.char_indices();
408	        let close_end = loop {
409	            let Some((i, c)) = it.next() else { return false };
410	            match c {
411	                '(' => depth += 1,
412	                ')' => {
413	                    depth -= 1;
414	                    if depth == 0 {
415	                        break i + 1;
416	                    }
417	                }
418	                _ => {}
419	            }
420	        };
421	        let after = bytes[close_end..].trim_start();
422	        after.starts_with('=')
423	            || after.starts_with('<')
424	            || after.starts_with('\u{228f}')
425	            || after.starts_with('@')
426	    }
427	    fn formula_atom(&mut self) -> Formula {
428	        self.ws();
429	        if self.rest().starts_with("last(") {
430	            self.pos += "last(".len();
431	            let t = self.term();
432	            self.expect(")");
433	            return Formula::Atom(Atom::Last(t));
434	        }
435	        if self.rest().starts_with('!') {
436	            let f = self.fact();
437	            self.expect("@");
438	            let tp = self.term();
439	            return Formula::Atom(Atom::Action(f, tp));
440	        }
441	        let save = self.pos;
442	        let mut is_nullary_fact = false;
443	        if self.rest().chars().next().is_some_and(|c| c.is_ascii_alphanumeric() || c == '_') {
444	            let _ = self.ident();
445	            if self.starts("(") {
446	                self.pos += 1;
447	                if self.starts(")") {
448	                    is_nullary_fact = true;
449	                }
450	            }
451	        }
452	        self.pos = save;
453	        if is_nullary_fact {
454	            let f = self.fact();
455	            self.expect("@");
456	            let tp = self.term();
457	            return Formula::Atom(Atom::Action(f, tp));
458	        }
459	        let t = self.term();
460	        self.ws();
461	        if self.eat("@") {
462	            let (name, args) = match t {
463	                Term::App(name, args) => (name, args),
464	                Term::Var(v) => {
465	                    assert_eq!(v.idx, 0, "action fact head with index");
466	                    (v.name, vec![])
467	                }
468	                other => panic!("action atom on non-fact term {other:?}"),
469	            };
470	            let tp = self.term();
471	            return Formula::Atom(Atom::Action(
472	                Fact { persistent: false, name, args, annotations: vec![] },
473	                tp,
474	            ));
475	        }
476	        if self.eat("=") {
477	            let r = self.term();
478	            return Formula::Atom(Atom::Eq(t, r));
479	        }
480	        if self.eat("\u{228f}") {
481	            let r = self.term();
482	            return Formula::Atom(Atom::Subterm(t, r));
483	        }
484	        if self.eat("<") {
485	            let r = self.term();
486	            return Formula::Atom(Atom::Less(t, r));
487	        }
488	        panic!("relation glyph expected at …{:?}", &self.rest()[..self.rest().len().min(50)]);
489	    }
490	}
