503	pub fn parse_rule_block(block: &str) -> (Rule, Option<AcVariants>) {
504	    let mut p = P::new(block);
505	    let mut r = p.rule_core();
506	    if p.starts("//") {
507	        r.loop_breakers = p.breaker_line();
508	    }
509	    p.expect("/*");
510	    if p.eat("has exactly the trivial AC variant") {
511	        p.expect("*/");
512	        return (r, None);
513	    }
514	    let mut ac = p.rule_core();
515	    let mut substitutions: Vec<Vec<(Term, Term)>> = Vec::new();
516	    if p.eat("variants (modulo AC)") {
517	        loop {
518	            if p.starts("*/") || p.starts("//") {
519	                break;
520	            }
521	            p.ws();
522	            if p.rest().chars().next().is_some_and(|c| c.is_ascii_digit()) {
523	                let n: usize = p.digits().parse().unwrap();
524	                p.expect(".");
525	                assert_eq!(n, substitutions.len() + 1, "group numbering");
526	                substitutions.push(Vec::new());
