568	/// Reconstruct the `Signature` from the web message-pane body (the declaration
569	/// lines only — no batch header comment).
570	pub fn parse_signature(decls: &str) -> Signature {
571	    let lines: Vec<&str> = decls.lines().collect();
572	    let mut builtins = Vec::new();
573	    let mut functions = Vec::new();
574	    let mut equations = Vec::new();
575	    let mut convergent = false;
576	    let mut i = 0;
577	    while i < lines.len() {
578	        let mut sect = String::from(lines[i]);
579	        let mut j = i + 1;
580	        while j < lines.len() && lines[j].starts_with(char::is_whitespace) {
581	            sect.push(' ');
582	            sect.push_str(lines[j].trim_start());
583	            j += 1;
584	        }
585	        if let Some(rest) = sect.strip_prefix("builtins:") {
586	            builtins = rest
587	                .split(',')
588	                .map(|s| s.trim().to_string())
589	                .filter(|s| !s.is_empty())
590	                .collect();
591	        } else if let Some(rest) = sect.strip_prefix("functions:") {
592	            functions = parse_function_items(rest);
593	        } else if let Some(rest) = sect.strip_prefix("equations") {
594	            let rest = rest.trim_start();
595	            let rest = if let Some(r) = rest.strip_prefix("[convergent]") {
596	                convergent = true;
597	                r.trim_start()
598	            } else {
599	                rest
600	            };
601	            let rest = rest.strip_prefix(':').expect("equations header colon");
602	            equations = parse_equations(rest);
603	        } else {
604	            panic!("unknown signature section: {sect:?}");
605	        }
606	        i = j;
607	    }
608	    // The `builtins:` line never lists `dest-pairing` (it induces no operators),
609	    // so recover it from the shown functions: a destructor `fst`/`snd` means the
610	    // theory used dest-pairing, and the renderer must flip its base pairing
611	    // symbols to destructors (else it re-adds constructor `fst/1` alongside the
612	    // shown `fst/1[destructor]`). This is a reconstruction detail; the real
613	    // adapter carries the builtin set directly.
614	    if functions
615	        .iter()
616	        .any(|f| f.destructor && (f.name == "fst" || f.name == "snd") && f.arity == 1)
617	    {
618	        builtins.push("dest-pairing".to_string());
619	    }
620	    Signature { builtins, functions, equations, convergent }
621	}
