623	fn parse_function_items(s: &str) -> Vec<FunctionDecl> {
624	    let mut p = P::new(s);
625	    let mut out = Vec::new();
626	    loop {
627	        p.ws();
628	        if p.rest().is_empty() {
629	            break;
630	        }
631	        let name: String = p.rest().chars().take_while(|c| *c != '/').collect();
632	        p.pos += name.len();
633	        p.expect("/");
634	        let arity: usize = p.digits().parse().unwrap();
635	        let (mut private, mut destructor) = (false, false);
636	        if p.rest().starts_with('[') {
637	            let end = p.rest().find(']').expect("unterminated attr");
638	            let attrs = &p.rest()[1..end];
639	            private = attrs.contains("private");
640	            destructor = attrs.contains("destructor");
641	            p.pos += end + 1;
642	        }
643	        out.push(FunctionDecl { name, arity, private, destructor });
644	        if !p.eat(",") {
645	            break;
646	        }
647	    }
648	    out
649	}
