651	fn parse_equations(s: &str) -> Vec<Equation> {
652	    let mut p = P::new(s);
653	    let mut out = Vec::new();
654	    loop {
655	        p.ws();
656	        if p.rest().is_empty() {
657	            break;
658	        }
659	        let lhs = p.term();
660	        p.expect("=");
661	        let rhs = p.term();
662	        out.push(Equation { lhs, rhs });
663	        if !p.eat(",") {
664	            break;
665	        }
666	    }
667	    out
668	}
