thread_local! {
    /// The per-character layout charge, always [`escaped_char_width`] in normal
    /// operation. Indirected through a cell so the acceptance suite can DOCTOR it
    /// (e.g. to glyph width) and prove the byte gate genuinely depends on the
    /// escaped charging — see `escaped_charging_is_load_bearing`. Never changed
    /// outside a test.
    static CHARGE: Cell<fn(char) -> usize> = Cell::new(escaped_char_width);
}

/// The active layout charge for one character (the escaped width in production).
fn char_charge(c: char) -> usize {
    CHARGE.with(|k| k.get())(c)
}

